#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M,K; scanf("%d %d %d",&N,&M,&K);
        int *freq = (int*)calloc(N+1,sizeof(int));
        for(int i=0;i<K;i++){
            int x; scanf("%d",&x);
            if(x<=N) freq[x]++;
        }
        int cnt=0;
        for(int i=1;i<=N;i++) if(freq[i]>1) cnt++;
        if(cnt==0){
            printf("0\n");
        }else{
            printf("%d",cnt);
            for(int i=1;i<=N;i++) if(freq[i]>1) printf(" %d",i);
            printf("\n");
        }
        free(freq);
    }
    return 0;
}

