import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            int M = fs.nextInt();
            int K = fs.nextInt();
            int[] freq = new int[N+1];
            for(int i=0;i<K;i++){
                int x = fs.nextInt();
                if(x<=N) freq[x]++;
            }
            List<Integer> list = new ArrayList<>();
            for(int i=1;i<=N;i++) if(freq[i]>1) list.add(i);
            if(list.isEmpty()) sb.append(0).append('\n');
            else{
                sb.append(list.size());
                for(int id:list) sb.append(' ').append(id);
                sb.append('\n');
            }
        }
        System.out.print(sb.toString());
    }
    static class FastScanner{
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1<<16];
        private int ptr=0, len=0;
        FastScanner(InputStream is){in=new BufferedInputStream(is);}        
        private int readByte(){
            if(ptr>=len){
                try{len=in.read(buffer);ptr=0;}catch(IOException e){return -1;}
                if(len<=0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt(){
            int c, sign=1, val=0;
            do{c=readByte();}while(c<=32 && c!=-1);
            if(c=='-'){sign=-1; c=readByte();}
            while(c>32 && c!=-1){val=val*10+(c-'0'); c=readByte();}
            return val*sign;
        }
    }
}

