import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        freq = [0]*(N+1)
        for _ in range(K):
            x = int(next(it))
            if x <= N:
                freq[x] += 1
        res = [str(i) for i in range(1,N+1) if freq[i] > 1]
        if not res:
            out_lines.append('0')
        else:
            out_lines.append(str(len(res)) + ' ' + ' '.join(res))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

